class Solution {
    public int nextBeautifulNumber(int n) {
        int count[] = new int[10];
        int result = n;
        for (int i = 0; i < 10; i++) {
            count[i] = 0;
        }
        while (result > 0) {
            int digit = result % 10;
            count[digit]++;
            result /= 10;
        }
        int maxCount = 0;
        for (int i = 0; i < 10; i++) {
            if (count[i] > maxCount) {
                maxCount = count[i];
            }
        }
        result = 1;
        for (int i = 0; i < 10; i++) {
            result *= 10;
            result += count[i];
        }
        return result;
    }
}
